const sessionId = $json.sessionId;
const userId = $json.userId;
const chatInput = $json.chatInput;
const companyId = $json.company_id;

if (!sessionId) {
  throw new Error('sessionId nao informado');
}

if (!userId) {
  throw new Error('userId nao informado');
}

if (!chatInput || !chatInput.trim()) {
  throw new Error('chatInput nao informado');
}

if (!companyId) {
  throw new Error('company_id nao informado');
}

return [{
  json: {
    ...$json,
    chatInput: chatInput.trim()
  }
}];

const companyId = $json.company_id;
const userId = $json.userId;

// Substitua este bloco por consulta real ao seu banco.
// Exemplo esperado: validar se o userId pertence ao company_id.
const mockMembership = true;

if (!mockMembership) {
  throw new Error(`Usuario ${userId} nao pertence a empresa ${companyId}`);
}

return [{
  json: {
    ...$json,
    accessValidated: true
  }
}];

const companyId = $json.company_id;

// Substitua este bloco por query no banco:
// select id, name, workspace_id, dataset_id from companies where id = $1
const companyContext = {
  company_id: companyId,
  company_name: 'Empresa Exemplo',
  workspace_id: 'workspace-demo',
  dataset_id: 'dataset-demo',
  timezone: 'America/Sao_Paulo',
  language: 'pt-BR'
};

return [{
  json: {
    ...$json,
    companyContext
  }
}];

const companyId = $json.company_id;

// Substitua por leitura real do catalogo semantico da empresa.
const semanticCatalog = {
  company_id: companyId,
  tables: ['FatoVendas', 'DimProduto', 'DimCliente', 'DimCalendario', 'DimRegiao'],
  dimensions: ['Produto', 'Cliente', 'Regiao', 'Data'],
  measures: ['Receita Total', 'Quantidade Vendida', 'Margem', 'Ticket Medio'],
  synonyms: {
    faturamento: 'Receita Total',
    receita: 'Receita Total',
    vendas: 'Quantidade Vendida',
    regiao: 'Regiao'
  },
  business_rules: [
    'Faturamento corresponde a medida Receita Total',
    'Ultimo mes usa calendario fechado da DimCalendario',
    'Cliente ativo significa cliente com compra nos ultimos 90 dias'
  ]
};

return [{
  json: {
    ...$json,
    semanticCatalog
  }
}];

const prompt = [
  'Voce e um analista de dados especializado em Power BI.',
  'Responda apenas com base no catalogo e nos dados retornados.',
  'Nao invente metricas ou dimensoes.',
  'Se a pergunta estiver ambigua, solicite esclarecimento.',
  '',
  `company_id: ${$json.company_id}`,
  `workspace_id: ${$json.companyContext.workspace_id}`,
  `dataset_id: ${$json.companyContext.dataset_id}`,
  '',
  'Catalogo:',
  JSON.stringify($json.semanticCatalog, null, 2),
  '',
  `Pergunta do usuario: ${$json.chatInput}`
].join('\n');

return [{
  json: {
    ...$json,
    llmPrompt: prompt
  }
}];

// Este node simula a saida de um LLM.
// Em producao, substitua por OpenAI, Azure OpenAI ou outro modelo.
const interpretedIntent = {
  intent: 'analytical_query',
  metric: 'Receita Total',
  dimension: 'Regiao',
  period: 'Ultimo trimestre',
  filters: [],
  confidence: 0.88,
  requiresClarification: false,
  daxTemplate: 'EVALUATE SUMMARIZECOLUMNS(...)'
};

return [{
  json: {
    ...$json,
    interpretedIntent
  }
}];

return [{
  json: {
    sessionId: $json.sessionId,
    company_id: $json.company_id,
    message: 'Sua pergunta ficou ambigua para o catalogo atual. Pode especificar melhor a metrica, periodo ou filtro desejado?',
    metadata: {
      status: 'clarification_required'
    }
  }
}];

const intent = $json.interpretedIntent;
const companyContext = $json.companyContext;

const daxQuery = [
  '-- Consulta gerada dinamicamente',
  `-- company_id: ${$json.company_id}`,
  `-- workspace_id: ${companyContext.workspace_id}`,
  `-- dataset_id: ${companyContext.dataset_id}`,
  '',
  `-- metric: ${intent.metric}`,
  `-- dimension: ${intent.dimension}`,
  `-- period: ${intent.period}`,
  '',
  'EVALUATE',
  'SUMMARIZECOLUMNS(',
  "  'DimRegiao'[Regiao],",
  '  "Receita Total", [Receita Total]',
  ')'
].join('\n');

return [{
  json: {
    ...$json,
    daxQuery
  }
}];

// Substitua este node por chamada real a API/servico que consulta o Power BI.
const queryResult = {
  rows: [
    { Regiao: 'Sudeste', ReceitaTotal: 1200000 },
    { Regiao: 'Sul', ReceitaTotal: 680000 },
    { Regiao: 'Nordeste', ReceitaTotal: 420000 }
  ],
  totals: {
    ReceitaTotal: 2300000
  },
  appliedFilters: ['Ultimo trimestre'],
  executionTimeMs: 842
};

return [{
  json: {
    ...$json,
    queryResult
  }
}];

const rows = $json.queryResult.rows || [];
const total = $json.queryResult.totals?.ReceitaTotal || 0;
const topRegion = rows[0]?.Regiao || 'N/A';
const topValue = rows[0]?.ReceitaTotal || 0;

const answer = [
  `O valor total encontrado foi R$ ${total.toLocaleString('pt-BR')}.`,
  `A regiao com maior resultado foi ${topRegion}, com R$ ${topValue.toLocaleString('pt-BR')}.`,
  'Se quiser, posso detalhar por produto, cliente ou comparar com outro periodo.'
].join(' ');

return [{
  json: {
    sessionId: $json.sessionId,
    company_id: $json.company_id,
    message: answer,
    metadata: {
      status: 'success',
      workspace_id: $json.companyContext.workspace_id,
      dataset_id: $json.companyContext.dataset_id,
      interpretedIntent: $json.interpretedIntent,
      daxQuery: $json.daxQuery,
      appliedFilters: $json.queryResult.appliedFilters,
      executionTimeMs: $json.queryResult.executionTimeMs,
      rows: rows
    }
  }
}];

// Persistencia opcional.
// Substitua por insert real no banco se quiser armazenar sessao, pergunta, DAX e resposta.
return [{
  json: {
    ...$json,
    persisted: true
  }
}];

return [{
  json: {
    status: 'error',
    message: $json.message || 'Erro nao tratado no fluxo'
  }
}];
